// Split the email into one item per attachment
const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;
  const binary = item.binary || {};

  for (const [key, attachment] of Object.entries(binary)) {
    output.push({
      json: {
        email_id: data.id,
        email_subject: data.subject || '',
        email_from: data.from?.value?.[0]?.address || data.from || '',
        email_body: (data.textPlain || data.snippet || '').substring(0, 2000),
        attachment_filename: attachment.fileName || 'unknown',
        attachment_mime: attachment.mimeType || '',
        attachment_size: attachment.fileSize || 0
      },
      binary: {
        attachment: attachment
      }
    });
  }
}

return output;

// Calculate SHA256 hash for VirusTotal lookup
const crypto = require('crypto');
const output = [];

for (const item of $input.all()) {
  const binaryData = item.binary.attachment;
  const buffer = Buffer.from(binaryData.data, 'base64');
  const hash = crypto.createHash('sha256').update(buffer).digest('hex');

  output.push({
    json: {
      ...item.json,
      file_hash: hash
    },
    binary: item.binary
  });
}

return output;

