// Combine VirusTotal + AI verdict into a single risk level
const item = $input.first();
const data = item.json;

const hashData = $('Compute SHA256 Hash of Attachment').item.json;

let maliciousCount = 0;
let suspiciousCount = 0;
let vtAvailable = false;

try {
  const vtData = $('Look Up Hash in VirusTotal').item.json;
  if (vtData && vtData.data && vtData.data.attributes) {
    const stats = vtData.data.attributes.last_analysis_stats || {};
    maliciousCount = stats.malicious || 0;
    suspiciousCount = stats.suspicious || 0;
    vtAvailable = true;
  }
} catch (e) {
  // File unknown to VirusTotal - treat as not-yet-seen
}

const aiVerdict = (data.message?.content || '').toLowerCase().trim();

let risk_level;
if (maliciousCount >= 3 || aiVerdict.includes('phishing')) {
  risk_level = 'danger';
} else if (maliciousCount > 0 || suspiciousCount >= 2 || aiVerdict.includes('suspicious')) {
  risk_level = 'suspicious';
} else {
  risk_level = 'safe';
}

return {
  json: {
    ...hashData,
    malicious_count: maliciousCount,
    suspicious_count: suspiciousCount,
    vt_available: vtAvailable,
    ai_verdict: aiVerdict,
    risk_level
  },
  binary: item.binary
};

